import re

def slugify(text):
    text = re.sub(r'[^a-zA-Z0-9]+', '-', text.strip().lower())
    return text.strip('-')

def unique_stable(items):
    seen = set()
    out = []
    for item in items:
        if item not in seen:
            seen.add(item)
            out.append(item)
    return out

def safe_divide(a, b):
    if b == 0:
        return None
    return a / b

