def balanced_parens(text):
    depth = 0
    for ch in text:
        if ch == '(':
            depth += 1
        elif ch == ')':
            depth -= 1
            if depth < 0:
                return False
    return depth == 0

import re

def camel_to_snake(name):
    first = re.sub('(.)([A-Z][a-z]+)', r'\1_\2', name)
    return re.sub('([a-z0-9])([A-Z])', r'\1_\2', first).lower()

def tokenize_tags(text):
    tags = []
    seen = set()
    for raw in text.split(','):
        tag = raw.strip().lower()
        if tag and tag not in seen:
            seen.add(tag)
            tags.append(tag)
    return tags

def coalesce(*values):
    for value in values:
        if value is not None:
            return value
    return None

def human_list(items):
    if not items:
        return ''
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f'{items[0]} and {items[1]}'
    return ', '.join(items[:-1]) + f', and {items[-1]}'

import json

def parse_json_lines(text):
    return [json.loads(line) for line in text.splitlines() if line.strip()]
